import React from 'react';
import {StyleSheet, View} from 'react-native';
import {GestureDetector, Gesture} from 'react-native-gesture-handler';
import Animated, {useSharedValue, useAnimatedStyle, withSpring, runOnJS} from 'react-native-reanimated';
export function WalletStack({cards, onDismissTop}: {cards: React.ReactNode[]; onDismissTop: () => void}) {
  const y = useSharedValue(0);
  const pan = Gesture.Pan().onUpdate(e => { y.value = Math.max(0, e.translationY); }).onEnd(e => { if (y.value > 100 || e.velocityY > 800) { y.value = withSpring(600, {damping: 22}, () => runOnJS(onDismissTop)()); } else { y.value = withSpring(0); }});
  const topStyle = useAnimatedStyle(() => ({transform: [{translateY: y.value}]}));
  return (<View style={s.root}>{cards.map((c, i) => { const offset = (cards.length - 1 - i) * 40; const isTop = i === cards.length - 1; return (<Animated.View key={i} style={[s.card, {top: offset, zIndex: i}, isTop && topStyle]}>{isTop ? <GestureDetector gesture={pan}><View style={{flex:1}}>{c}</View></GestureDetector> : c}</Animated.View>); })}</View>);
}
const s = StyleSheet.create({root:{flex:1, padding:16}, card:{position:'absolute', left:16, right:16, height:240, borderRadius:16, backgroundColor:'#1C1C1E', padding:20, shadowColor:'#000', shadowOpacity:0.3, shadowRadius:14}});

