import React, {useState} from 'react';
import {StyleSheet, View, TextInput, Pressable, Text} from 'react-native';
import Animated, {useSharedValue, useAnimatedStyle, withRepeat, withTiming, cancelAnimation} from 'react-native-reanimated';
export function VoiceSearchInput({value, onChange, onStartVoice, onStopVoice, listening}: {value: string; onChange: (v: string) => void; onStartVoice: () => void; onStopVoice: () => void; listening: boolean}) {
  const pulse = useSharedValue(1);
  React.useEffect(() => { if (listening) pulse.value = withRepeat(withTiming(1.2, {duration: 600}), -1, true); else { cancelAnimation(pulse); pulse.value = 1; }}, [listening]);
  const style = useAnimatedStyle(() => ({transform: [{scale: pulse.value}]}));
  return (<View style={s.row}><TextInput value={value} onChangeText={onChange} placeholder='Search' placeholderTextColor='#8E8E93' style={s.input}/><Pressable onPress={listening ? onStopVoice : onStartVoice}><Animated.View style={[s.mic, style, listening && s.micActive]}><Text style={s.glyph}>{'🎤'}</Text></Animated.View></Pressable></View>);
}
