// CollapsibleBlock.tsx (concept)
import React, {useState} from 'react';
import {StyleSheet, View, Text} from 'react-native';
import {GestureDetector, Gesture} from 'react-native-gesture-handler';
import Animated, {useSharedValue, useAnimatedStyle, withSpring, runOnJS} from 'react-native-reanimated';
export function CollapsibleBlock({summary, full}: {summary: string; full: string}) {
  const [collapsed, setCollapsed] = useState(false);
  const t = useSharedValue(collapsed ? 0 : 1);
  React.useEffect(() => { t.value = withSpring(collapsed ? 0 : 1, {damping: 18, stiffness: 240}); }, [collapsed]);
  const pinch = Gesture.Pinch().onEnd(e => { if (e.scale < 0.7) runOnJS(setCollapsed)(true); else if (e.scale > 1.3) runOnJS(setCollapsed)(false); });
  const style = useAnimatedStyle(() => ({opacity: t.value, maxHeight: 200 * t.value + 24}));
  const sumStyle = useAnimatedStyle(() => ({opacity: 1 - t.value}));
  return (<GestureDetector gesture={pinch}><View style={s.wrap}><Animated.Text style={[s.summary, sumStyle]}>{summary}</Animated.Text><Animated.View style={style}><Text style={s.full}>{full}</Text></Animated.View></View></GestureDetector>);
}
const s = StyleSheet.create({wrap:{padding:16, backgroundColor:'#1C1C1E', borderRadius:12}, summary:{color:'#8E8E93', fontStyle:'italic', position:'absolute', padding:16}, full:{color:'#fff'}});

